class Solution:
    def minimumChanges(self, s: str, k: int) -> int:
        n = len(s)
        # Precompute cost for all substrings [i..j] to be semi-palindromes
        cost = [[0] * n for _ in range(n)]

        for i in range(n):
            for j in range(i + 1, n):
                length = j - i + 1
                # Check all possible d values for semi-palindrome
                for d in range(1, length):
                    if length % d != 0:
                        continue
                    # Check if the substring is a semi-palindrome
                    for m in range(d):
                        for l in range(1, length // d):
                            left = i + m + l * d
                            right = i + (d - 1 - m) + l * d
                            if left >= j or right >= j:
                                break
                            if s[left] != s[right]:
                                cost[i][j] += 1
                # If length is 1, it's not a semi-palindrome
                if length == 1:
                    cost[i][j] = float('inf')

        # DP with memoization
        dp = [[float('inf')] * (k + 1) for _ in range(n)]
        dp[0][1] = cost[0][0]

        for i in range(1, n):
            for parts in range(1, k + 1):
                for j in range(i):
                    if parts > 1:
                        dp[i][parts] = min(dp[i][parts], dp[j][parts - 1] + cost[j + 1][i])

        return dp[n - 1][k]
